  font-size: 16px;\r\n  font-weight: 400; // Regular\r\n}\r\n\r\n.section{\r\n  padding: 80px 0;\r\n}\r\n\r\n.text-center {\r\n  text-align: center;}\r\n\r\n.section__title{\r\n  margin-bottom: 45px;\r\n\r\n  &--white {\r\n    color: $color-white;}\r\n\r\n}\r\n\r\n\r\n\r\ninput {\r\n    width: 100%;\r\n    height: 50px;\r\n    background: $color-bg-main !important;\r\n    border: none;\r\n    border-radius: 15px;\r\n    padding: 0 25px;\r\n\r\n    font-size: 16px;\r\n    color: $color-text;\r\n    box-shadow: 3px 3px 8px 0.5px rgba(0, 0, 0, 0.1);\r\n    transition: $transition;\r\n\r\n    &::placeholder {\r\n      color: rgba(29, 53, 17, 0.5);\r\n    }\r\n\r\n    &:focus {\r\n      outline: none;\r\n      background: #fff !important;\r\n      box-shadow: 0 4px 15px rgba(108, 192, 50, 0.1);\r\n    }\r\n  }\r\n\r\n\r\n  ","* {\r\n\tmargin: 0;\r\n\tpadding: 0;\r\n\tbox-sizing: border-box;\r\n}\r\n\r\n*:before,\r\n*:after {\r\n\tbox-sizing: border-box;\r\n}\r\n\r\nhtml, body, div, span, applet, object, iframe,\r\nh1, h2, h3, h4, h5, h6, p, blockquote, pre,\r\na, abbr, acronym, address, big, cite, code,\r\ndel, dfn, em, img, ins, kbd, q, s, samp,\r\nsmall, strike, strong, sub, sup, tt, var,\r\nb, u, i, center,\r\ndl, dt, dd, ol, ul, li,\r\nfieldset, form, label, legend,\r\ntable, caption, tbody, tfoot, thead, tr, th, td,\r\narticle, aside, canvas, details, embed,\r\nfigure, figcaption, footer, header, hgroup,\r\nmenu, nav, output, ruby, section, summary,\r\ntime, mark, audio, video {\r\n\tmargin: 0;\r\n\tpadding: 0;\r\n\tborder: 0;\r\n\t\r\n\tvertical-align: baseline;\r\n}\r\n\r\narticle, aside, details, figcaption, figure,\r\nfooter, header, hgroup, menu, nav, section {\r\n\tdisplay: block;\r\n}\r\n\r\nhtml {\r\n\tscroll-behavior: smooth;\r\n}\r\n\r\nbody {\r\n\t\r\n\t-webkit-font-smoothing: antialiased;\r\n\t-moz-osx-font-smoothing: grayscale;\r\n}\r\n\r\n\r\n\r\nol, ul {\r\n\tlist-style: none;\r\n}\r\n\r\nblockquote, q {\r\n\tquotes: none;\r\n}\r\n\r\nblockquote:before, blockquote:after,\r\nq:before, q:after {\r\n\tcontent: '';\r\n\tcontent: none;\r\n}\r\n\r\ntable {\r\n\tborder-collapse: collapse;\r\n\tborder-spacing: 0;\r\n}\r\n\r\ninput, button, textarea, select {\r\n\tfont: inherit;\r\n\tcolor: inherit;\r\n\tbackground: transparent;\r\n\tborder: none;\r\n\toutline: none;\r\n}\r\n\r\nbutton {\r\n\tcursor: pointer;\r\n}\r\n\r\na {\r\n\tcolor: inherit;\r\n\ttext-decoration: none;\r\n}\r\n\r\nimg {\r\n\tmax-width: 100%;\r\n\theight: auto;\r\n\tdisplay: block;\r\n}\r\n\r\nhr {\r\n\tmargin: 0;\r\n\tpadding: 0;\r\n\tborder: none;\r\n\tbackground-color: transparent;\r\n}\r\n\r\ntextarea {\r\n\tresize: none;\r\n}\r\n\r\ninput[type=\"search\"]::-webkit-search-decoration,\r\ninput[type=\"search\"]::-webkit-search-cancel-button {\r\n\t-webkit-appearance: none;\r\n}","@charset \"UTF-8\";\n.container {\n  max-width: 1170px;\n  padding: 0 15px;\n  width: 100%;\n  margin: 0 auto;\n}\n\nbody {\n  background-color: #FFF8ED;\n  font-family: \"Gilroy\";\n  font-size: 16px;\n  line-height: 1.4;\n  color: #263D15;\n}\n\nh1 {\n  font-size: 48px;\n  line-height: 1.2;\n  font-weight: 700;\n}\n\nh2 {\n  font-size: 40px;\n  font-weight: 600;\n  line-height: 1.2;\n}\n\nh3 {\n  font-size: 28px;\n  font-weight: 600;\n  line-height: 1.2;\n}\n\nh4 {\n  font-size: 20px;\n  font-weight: 600;\n  line-height: 1.2;\n}\n\np {\n  font-size: 16px;\n  font-weight: 400;\n}\n\n.section {\n  padding: 80px 0;\n}\n\n.text-center {\n  text-align: center;\n}\n\n.section__title {\n  margin-bottom: 45px;\n}\n.section__title--white {\n  color: #FFFFFF;\n}\n\ninput {\n  width: 100%;\n  height: 50px;\n  background: #FFF8ED !important;\n  border: none;\n  border-radius: 15px;\n  padding: 0 25px;\n  font-size: 16px;\n  color: #263D15;\n  box-shadow: 3px 3px 8px 0.5px rgba(0, 0, 0, 0.1);\n  transition: all 0.3s ease;\n}\ninput::placeholder {\n  color: rgba(29, 53, 17, 0.5);\n}\ninput:focus {\n  outline: none;\n  background: #fff !important;\n  box-shadow: 0 4px 15px rgba(108, 192