ctive {\n  background: #5ABC15;\n  color: #FFFFFF;\n  box-shadow: 3px 3px 8px 0.5px rgba(0, 0, 0, 0.1);\n}\n\n.faq__content {\n  display: flex;\n  flex-direction: column;\n  gap: 20px;\n}\n\n.faq-item {\n  background-color: #FFF8ED;\n  padding: 25px;\n  border-radius: 30px;\n}\n.faq-item__header {\n  margin-bottom: 0;\n  font-weight: 500;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  width: 100%;\n  transition: all 0.3s ease;\n}\n.faq-item__header i {\n  font-size: 24px;\n  line-height: 1;\n  transition: transform 0.3s ease;\n}\n.faq-item__body {\n  display: grid;\n  grid-template-rows: 0fr;\n  transition: grid-template-rows 0.3s ease;\n  overflow: hidden;\n}\n.faq-item__text {\n  min-height: 0;\n  background-color: #EFF6CB;\n  font-weight: 500;\n  transition: all 0.3s ease;\n  border-radius: 15px;\n}\n.faq-item.active__header i {\n  transform: rotate(180deg);\n}\n.faq-item.active .faq-item__body {\n  margin-top: 20px;\n  grid-template-rows: 1fr;\n}\n.faq-item.active .faq-item__text {\n  padding: 20px;\n}\n\n.faq__content {\n  display: none;\n}\n.faq__content.active {\n  display: flex;\n}\n\n.about-tabs__nav {\n  display: flex;\n  justify-content: center;\n  gap: 100px;\n  margin-bottom: -1px;\n}\n.about-tabs__btn {\n  padding: 15px 40px;\n  font-size: 18px;\n  font-weight: 600;\n  border: none;\n  background: transparent;\n  color: #263D15;\n  cursor: pointer;\n  transition: all 0.3s ease;\n  border-radius: 20px 20px 0 0;\n}\n.about-tabs__btn.active {\n  background: #5ABC15;\n  color: #FFFFFF;\n}\n.about-tabs__content {\n  display: none;\n  background: #5ABC15;\n  border-radius: 40px;\n  padding: 60px 80px;\n  color: #fff;\n}\n.about-tabs__content.active {\n  display: block;\n}\n@media (max-width: 768px) {\n  .about-tabs__content {\n    padding: 40px 25px;\n    border-radius: 30px;\n  }\n}\n.about-tabs__grid {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 60px;\n  align-items: start;\n}\n@media (max-width: 768px) {\n  .about-tabs__grid {\n    grid-template-columns: 1fr;\n    gap: 40px;\n  }\n}\n.about-tabs__title {\n  font-size: 32px;\n  margin-bottom: 25px;\n}\n.about-tabs__text {\n  font-size: 16px;\n  line-height: 1.6;\n  opacity: 0.95;\n}\n.about-tabs__list {\n  list-style: none;\n  padding: 0;\n  display: flex;\n  flex-direction: column;\n  gap: 30px;\n}\n.about-tabs__item {\n  position: relative;\n  padding-left: 20px;\n}\n.about-tabs__item::before {\n  content: \"•\";\n  position: absolute;\n  left: 0;\n  top: 0;\n  font-size: 20px;\n}\n.about-tabs__item-title {\n  display: block;\n  font-weight: 700;\n  font-size: 16px;\n  margin-bottom: 5px;\n  font-family: \"Gilroy\", sans-serif;\n}\n.about-tabs__item-desc {\n  font-size: 14px;\n  line-height: 1.4;\n  display: block;\n  opacity: 0.9;\n}\n\n.footer-cta {\n  margin-bottom: 100px;\n}\n\n.footer-cta__content {\n  display: flex;\n  justify-content: space-around;\n  align-items: center;\n}\n.footer-cta__content .call-us {\n  margin-top: 15px;\n  display: flex;\n  justify-content: space-between;\n}\n\n.footer-cta__content--right h3 {\n  margin-bottom: 15px;\n}\n.footer-cta__content--right p {\n  font-weight: 500;\n}\n\n.footer {\n  background-color: #EFF6CB;\n  padding: 40px 0;\n  color: #263D15;\n}\n.footer__wrapper {\n  display: grid;\n  grid-template-columns: 200px 1fr;\n  grid-template-areas: \"logo header\" \"logo main\";\n  column-gap: 60px;\n  row-gap: 40px;\n  align-items: start;\n}\n@media (max-width: 991px) {\n  .footer__wrapper {\n    grid-template-columns: 1fr;\n    grid-template-areas: \"logo\" \"header\" \"main\";\n    row-gap: 30px;\n    text-align: center;\n  }\n}\n.footer__logo-block {\n  grid-area: logo;\n}\n.footer__logo {\n  max-width: 100%;\n  height: auto;\n}\n.footer__header {\n  grid-area: header;\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 30px;\n}\n@media (max-width: 768px) {\n  .footer__header {\n    grid-template-columns: 1fr;\n  }\n}\n.footer__header--one h3 {\n  font-size: 20px;\n  font-weight: 600;\n  margin: 0 0 5px 0;\n}\n.footer__header--one span {\n  font-size: 14px;\n  opacity: 0.4;\n  display: block;\n}\n.footer__header--two a {\n  font-size: 20px;\n  font-weight: 600;\n  opacity: 0.4;\n  text-decoration: none;\n  transition: all 0.3s ease;\n}\n.footer__header--two a:hover {\n  opacity: 1;\n}\n.footer__header__three span {\n  display: block;\n  font-size: 12px;\n  line-height: 1.4;\n}\n.footer__main {\n  grid-area: main;\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 30px;\n}\n@media (max-width: 768px) {\n  .footer__main {\n    grid-template-columns: 1fr;\n  }\n}\n.footer__list {\n  list-style: none;\n  padding: 0;\n  margin: 0;\n  display: flex;\n  flex-direction: column;\n  gap: 14px;\n}\n.footer__list li a {\n  color: inherit;\n  text-decoration: none;\n  font-size: 14px;\n  font-weight: 500;\n  transition: all 0.3s ease;\n}\n.footer__list li a:hover {\n  opacity: 0.7;\n  padding-left: 5px;\n}\n.footer__socials-title {\n  display: block;\n  font-size: 14px;\n  font-weight: 500;\n  margin-bottom: 15px;\n}\n.footer__socials-icons {\n  display: flex;\n  gap: 15px;\n}\n@media (max-width: 768px) {\n  .footer__socials-icons {\n    justify-content: center;\n  }\n}\n.footer__social-link {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  width: 44px;\n  height: 44px;\n  background-color: #263D15;\n  color: #EFF6CB;\n  font-weight: 400;\n  border-radius: 50%;\n  font-size: 24px;\n  text-decoration: none;\n  transition: all 0.3s ease;\n}\n.footer__social-link:hover {\n  transform: all 0.3s ease;\n  background-color: #5ABC15;\n}","@font-face {\r\n\tfont-family: 'Gilroy';\r\n\tsrc: url('../fonts/Gilroy-Regular.woff') format('woff');\r\n\tfont-weight: 400;\r\n\tfont-style: normal;\r\n}\r\n\r\n@font-face {\r\n\tfont-family: 'Gilroy';\r\n\tsrc: url('../fonts/Gilroy-Medium.woff') format('woff');\r\n\tfont-weight: 500;\r\n\tfont-style: normal;\r\n}\r\n\r\n@font-face {\r\n\tfont-family: 'Gilroy';\r\n\tsrc: url('../fonts/Gilroy-Semibold.woff') format('woff');\r\n\tfont-weight: 600;\r\n\tfont-style: normal;\r\n}\r\n\r\n@font-face {\r\n\tfont-family: 'Gilroy';\r\n\tsrc: url('../fonts/Gilroy-Bold.woff') format('woff');\r\n\tfont-weight: 700;\r\n\tfont-style: normal;\r\n}\r\n\r\n@font-face {\r\n\tfont-family: 'Gilroy';\r\n\tsrc: url('../fonts/Gilroy-Black.woff') format('woff');\r\n\tfont-weight: 900;\r\n\tfont-style: normal;\r\n}","\r\n.btn {\r\n  // Базовые стили из твоего запроса\r\n  display: inline-block;\r\n  padding: 14px 111px;\r\n  background-color: $color-secondary;\r\n  color: $color-white;\r\n  border-radius: 15px;\r\n  font-size: 16px;\r\n  font-weight: 500; // Medium\r\n  \r\n  // Убираем дефолтные стили кнопки\r\n  border: none;\r\n  cursor: pointer;\r\n  text-align: center;\r\n  text-decoration: none;\r\n  transition: $transition !important;\r\n  \r\n  // Эффект при наведении\r\n  &:hover {\r\n    background: $color-hover;\r\n    transform: translateY(-2px); // Легкий подъем кнопки\r\n    box-shadow: 0 5px 15px rgba($color-primary, 0.3);\r\n  }\r\n\r\n  // Эффект при клике\r\n  &:active {\r\n    background: $color-focus;\r\n    transform: translateY(0);\r\n  }\r\n\r\n  // Адаптив для мобилок (чтобы кнопка не была шире экрана)\r\n  @media (max-width: 480px) {\r\n    padding: 14px 40px;\r\n    width: 100%;\r\n  }\r\n\r\n    // Вариант для полной ширины (например, в футере)\r\n    &--full {\r\n      width: 100%;\r\n      padding-left: 0;\r\n      padding-right: 0;\r\n      \r\n    }\r\n}",".menu__link{\r\n    font-size: 14px;\r\n    color: #10140E;\r\n    transition: $transition;\r\n\r\n    &:hover{\r\n        color: $color-secondary;\r\n    }\r\n}",".header {\r\n  position: absolute; // Чтобы шапка была поверх баннера\r\n  top: 55px;\r\n  left: 0;\r\n  right: 0;\r\n  z-index: 10;\r\n\r\n  &__top-bar {\r\n    background-color: $color-bg-main;\r\n    border-radius: 50px; // Сильное закругление как на макете\r\n    padding: 10px 40px;\r\n    display: flex;\r\n    align-items: center;\r\n    justify-content: space-between;\r\n    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.05);\r\n  }\r\n\r\n  &__logo {\r\n    img {\r\n      height: 50px; // Отрегулируй под свой лого\r\n      display: block;\r\n    }\r\n  }\r\n\r\n  &__nav {\r\n    display: flex;\r\n    gap: 30px;\r\n    \r\n    @media (max-width: 992px) {\r\n      display: none; // Скрываем на планшетах, оставляем бургер\r\n    }\r\n  }\r\n\r\n  &__badge {\r\n    background: $color-badge;\r\n    color: $color-white;\r\n    font-size: 14px;\r\n    font-weight: 500;\r\n    padding: 6px 40px;\r\n    border-radius: 0 0 20px 20px;\r\n    width: fit-content;\r\n    margin: 0 auto;\r\n    text-align: center;\r\n  }\r\n\r\n\r\n}\r\n\r\n\r\n\r\n.header__burger {\r\n  // 1. Сброс дефолтных стилей кнопки\r\n  background: none;\r\n  border: none;\r\n  cursor: pointer;\r\n  padding: 0;\r\n  \r\n  // 2. Размеры самой кнопки (зоны клика)\r\n  width: 24px;\r\n  height: 17px;\r\n  position: relative; // Обязательно для позиционирования линий внутри\r\n\r\n  // 3. Стили для центральной линии (span)\r\n  span,\r\n  &::before,\r\n  &::after {\r\n    content: ''; // Для псевдоэлементов\r\n    position: absolute;\r\n    left: 0;\r\n    width: 100%;\r\n    height: 3px; // Толщина линий\r\n    background-color: #4E8528; // Темный цвет из переменных\r\n    border-radius: 50px; // Закругленные края линий\r\n    transition: $transition;\r\n  }\r\n\r\n  // Позиционирование линий\r\n  &::before {\r\n    top: 0; // Верхняя линия\r\n  }\r\n\r\n  span {\r\n    top: 7px; // Центральная линия (высота 20px / 2 - 1px толщины)\r\n  }\r\n\r\n  &::after {\r\n    bottom: 0; // Нижняя линия\r\n  }\r\n\r\n  // 4. Эффект при наведении (опционально)\r\n  &:hover {\r\n    span,\r\n    &::before,\r\n    &::after {\r\n      background-color: $color-secondary; \r\n    }\r\n  }\r\n}\r\n\r\n\r\n.header__icon{\r\n    transition: $transition;\r\n    border-radius: 50px;\r\n\r\n    &:hover{\r\n        box-shadow: 0 5px 15px rgba($color-primary, 0.3);\r\n    transform: translateY(-2px);\r\n    }\r\n\r\n    &:active{\r\n        transform: translateY(0);\r\n    }\r\n}\r\n\r\n",".hero {\r\n  position: relative;\r\n  display: flex;\r\n  align-items: center;\r\n  background: url('../images/hero-bg.jpg') no-repeat center / cover;\r\n  padding-top: 218px;\r\n  padding-bottom: 169px;\r\n\r\n  &::before {\r\n    content: '';\r\n    position: absolute;\r\n    top: 0;\r\n    left: 0;\r\n    width: 100%;\r\n    height: 100%;\r\n    background: linear-gradient(270.05deg, rgba(239, 246, 203, 0.1) 0.04%, rgba(126, 201, 74, 0.6) 56.02%, rgba(78, 133, 40, 0.8) 78.78%, rgba(38, 61, 21, 0.9) 99.96%);\r\n    z-index: 1;\r\n  }\r\n\r\n  .container {\r\n    position: relative;\r\n    z-index: 2;\r\n  }\r\n\r\n  &__content {\r\n    max-width: 650px;\r\n    color: $color-white;\r\n  }\r\n\r\n  &__title {\r\n    margin-bottom: 35px;\r\n  }\r\n\r\n  &__text {\r\n    margin-bottom: 52px;\r\n    font-size: 18px;\r\n  }\r\n}\r\n\r\n\r\n\r\n.how-it-works {\r\n  \r\n\r\n  &__grid {\r\n    display: grid;\r\n    grid-template-columns: repeat(2, 1fr);\r\n    gap: 40px; \r\n\r\n    @media (max-width: 768px) {\r\n      grid-template-columns: 1fr;\r\n      gap: 30px;\r\n    }\r\n  }\r\n}\r\n\r\n.card-step {\r\n  position: relative;\r\n\r\n  &__inner {\r\n    background-color: $color-bg-card;\r\n    border-radius: 30px;\r\n    padding: 40px 60px;\r\n    height: 100%;\r\n    transition: transform 0.3s ease;\r\n\r\n    @media (max-width: 992px) {\r\n      padding: 40px;\r\n    }\r\n\r\n    &:hover {\r\n      transform: translateY(-5px);\r\n    }\r\n  }\r\n\r\n  &__number {\r\n    position: absolute;\r\n    top: 0;\r\n    right: 0;\r\n    transform: translate(30%, -30%);\r\n    \r\n    width: 50px;\r\n    height: 50px;\r\n    background-color: $color-secondary;\r\n    color: $color-white;\r\n    border-radius: 50%;\r\n    \r\n    display: flex;\r\n    align-items: center;\r\n    justify-content: center;\r\n    font-size: 16px;\r\n    font-weight: 800; \r\n    z-index: 2;\r\n    border: 5px solid $color-bg-main; \r\n\r\n    @media (max-width: 992px) {\r\n      width: 50px;\r\n      height: 50px;\r\n      font-size: 24px;\r\n    }\r\n  }\r\n\r\n  &__title {\r\n    margin-bottom: 25px;\r\n  }\r\n\r\n  &__text {\r\n   \r\n  }\r\n}\r\n\r\n\r\n\r\n.features {\r\n\r\n\r\n\r\n  &__grid {\r\n    display: grid;\r\n    // Создаем 3 колонки одинаковой ширины\r\n    grid-template-columns: repeat(3, 1fr);\r\n    // Расстояние между карточками\r\n    gap: 30px; \r\n\r\n    @include tablet {\r\n      grid-template-columns: repeat(2, 1fr); // На планшетах — в две колонки\r\n    }\r\n\r\n    @include mobile {\r\n      grid-template-columns: 1fr; // На телефонах — в одну колонку\r\n      gap: 20px;\r\n    }\r\n  }\r\n}\r\n\r\n// Стили для карточки преимущества\r\n.card-feature {\r\n  background-color: $color-bg-card; // Светло-салатовый фон карточек\r\n  border-radius: 15px; // Сильное закругление как на макете\r\n  padding: 30px 35px;\r\n  display: flex;\r\n  align-items: center; // Центрируем иконку и текст по вертикали\r\n  gap: 20px; // Расстояние между иконкой и текстом\r\n  height: 100%; // Чтобы все карточки были одной высоты\r\n\r\n  \r\n\r\n  &__icon {\r\n    width: 72px; // Фиксированная ширина для иконки\r\n    height: 72px; // Фиксированная высота\r\n    flex-shrink: 0; // Чтобы иконка не сжималась, если текст длинный\r\n    object-fit: contain; // Чтобы SVG не искажался\r\n\r\n  \r\n  }\r\n\r\n  &__title {\r\n    font-size: 18px;\r\n    font-weight: 500;\r\n  }\r\n\r\n \r\n\r\n  // Модификатор для карточки с длинным текстом (если нужно)\r\n  &--large-text {\r\n    .card-feature__text {\r\n      font-weight: 400; // Regular для длинного текста\r\n    }\r\n  }\r\n\r\n\r\n}\r\n\r\n\r\n\r\n\r\n\r\n.programs {\r\n  background: $gradient-accent; // Градиент на всю секцию\r\n  padding-top: 50px;\r\n  color: $color-text;\r\n  border-radius: 0 0 30px 30px; // Закругляем только нижние углы\r\n\r\n \r\n\r\n  &__tabs {\r\n    display: flex;\r\n    justify-content: center;\r\n    gap: 100px;\r\n  }\r\n\r\n  &__tab {\r\n    padding: 22px 99px;\r\n    border: none;\r\n    border-radius: 30px 30px 0 0;\r\n    font-size: 28px;\r\n    font-weight: 500;\r\n    cursor: pointer;\r\n    background: rgba($color-bg-card, 0.6);\r\n    color: #4A6D2F;\r\n    transition: all 0.3s ease;\r\n\r\n    &.active {\r\n      background: $color-bg-card; // Бежевый фон из макета\r\n      color: $color-text;\r\n    }\r\n  }\r\n\r\n  &__board {\r\n    width: 100%;\r\n    background-color: $color-bg-card; // Полоса на весь экран\r\n    padding: 60px 0 100px;\r\n    border-radius: 30px;\r\n    border-bottom: 40px solid transparent; // Для мягкого перехода вниз\r\n  }\r\n\r\n  &__inner {\r\n    display: flex;\r\n    gap: 50px;\r\n    align-items: flex-start;\r\n  }\r\n\r\n  &__menu { flex: 1; }\r\n  &__label { font-size: 24px; margin-bottom: 30px; font-weight: 600; }\r\n}\r\n\r\n// Навигация дней и калорий\r\n.days-nav, .calories-nav {\r\n  display: flex;\r\n  gap: 10px;\r\n  margin-bottom: 30px;\r\n}\r\n\r\n.day-link, .cal-btn {\r\n  padding: 12px 18px;\r\n  border-radius: 12px;\r\n  border: none;\r\n  background: #D8E4B0; // Светло-зеленый из макета\r\n  font-weight: 500;\r\n  color: $color-text;\r\n  cursor: pointer;\r\n  transition: 0.3s;\r\n\r\n  &.active {\r\n    background: $color-secondary; // Активный зеленый\r\n    color: $color-white;\r\n  }\r\n}\r\n\r\n// Сетка и карточки еды\r\n.food-grid {\r\n  display: grid;\r\n  grid-template-columns: repeat(3, 1fr);\r\n  gap: 20px;\r\n}\r\n\r\n.food-card {\r\n  background: $color-white;\r\n  border-radius: 20px;\r\n  padding: 25px;\r\n  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.03);\r\n\r\n  &__img {\r\n    width: 100%;\r\n    margin-bottom: 20px;\r\n    object-fit: contain;\r\n  }\r\n\r\n  &__tag {\r\n    font-size: 13px;\r\n    color: #999;\r\n    margin-bottom: 8px;\r\n    display: block;\r\n  }\r\n\r\n  &__title {\r\n    font-size: 17px;\r\n    font-weight: 500;\r\n    line-height: 1.4;\r\n  }\r\n}\r\n\r\n// Сайдбар заказа\r\n.sidebar {\r\n  width: 360px;\r\n \r\n\r\n  &__section { margin-bottom: 35px; }\r\n  &__caption { margin-bottom: 15px; font-size: 18px; }\r\n\r\n  &__details {\r\n    padding: 30px 0;\r\n    border-top: 1px dashed rgba(0, 0, 0, 0.1);\r\n    font-size: 16px;\r\n  }\r\n\r\n  &__row {\r\n    display: flex;\r\n    justify-content: space-between;\r\n    margin-bottom: 12px;\r\n    .discount-val { font-size: 14px; color: #999; }\r\n  }\r\n}\r\n\r\n// Переключатель 7/28 дней\r\n.duration-toggle {\r\n  display: flex;\r\n  gap: 12px;\r\n  \r\n  &__btn {\r\n    flex: 1;\r\n    padding: 14px 10px;\r\n    border: none;\r\n    border-radius: 15px;\r\n    font-size: 16px;\r\n    font-weight: 500;\r\n    cursor: pointer;\r\n    background: #FDFEFA; // Цвет неактивной кнопки (кремовый)\r\n    color: #333;\r\n    transition: all 0.3s ease;\r\n\r\n    &.active {\r\n      background: $color-secondary;\r\n      color: $color-white;\r\n      // Тень как на скриншоте\r\n      box-shadow: 3px 3px 8px 0.5px rgba(0, 0, 0, 0.1);  \r\n    }\r\n  }\r\n}\r\n\r\n\r\n// Финальная цена\r\n.total-price {\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: space-between;\r\n  margin-bottom: 30px;\r\n\r\n  &__label { font-size: 24px; font-weight: 600; }\r\n  \r\n  &__amount {\r\n    display: flex;\r\n    align-items: center;\r\n    gap: 15px;\r\n  }\r\n\r\n  .old-price {\r\n    color: #999;\r\n    text-decoration: line-through;\r\n    font-size: 18px;\r\n  }\r\n\r\n  .current-price {\r\n    background: $color-secondary;\r\n    color: $color-white;\r\n    padding: 8px 18px;\r\n    border-radius: 12px;\r\n    font-size: 22px;\r\n    font-weight: 700;\r\n  }\r\n}\r\n\r\n\r\n\r\n.benefits__grid{\r\n    display: grid;\r\n    grid-template-columns: repeat(4, 1fr);\r\n    gap: 30px;\r\n    \r\n    @include tablet {\r\n        grid-template-columns: repeat(2, 1fr);\r\n        gap: 20px;\r\n    }\r\n    \r\n    @include mobile {\r\n        grid-template-columns: 1fr;\r\n        gap: 15px;\r\n}\r\n}\r\n\r\n.benefit-item__icon img{\r\n    border-radius: 30px;\r\n    margin-bottom: 30px;\r\n}\r\n\r\n\r\n.benefit-item__text{\r\n    font-size: 18px;\r\n    font-weight: 500;\r\nline-height: 1.2;\r\npadding: 0 20px;  }\r\n\r\n\r\n\r\n.delivery {\r\n\r\n\r\n  &__block {\r\n    display: flex;\r\n    align-items: center;\r\n    justify-content: space-between;\r\n    gap: 60px;\r\n\r\n    @include tablet {\r\n      flex-direction: column;\r\n      align-items: flex-start;\r\n      gap: 40px;\r\n    }\r\n  }\r\n\r\n  &__text-wrapper {\r\n    flex: 0 0 40%; // Текст занимает чуть больше трети\r\n    \r\n    @include tablet {\r\n      flex: 0 0 100%;\r\n    }\r\n  }\r\n\r\n  &__title {\r\n    \r\n    font-weight: 700;\r\n    line-height: 1.1;\r\n    margin-bottom: 30px;\r\n    \r\n    @include tablet {\r\n      font-size: 34px;\r\n    }\r\n  }\r\n\r\n  &__text {\r\n    font-size: 16px;\r\n\r\n  }\r\n\r\n  &__map {\r\n    flex: 0 0 55%;\r\n    border-radius: 30px; // Скругление в стиле Apple\r\n    overflow: hidden;\r\n    // Тень для объема, как в премиальных интерфейсах\r\n    box-shadow: 0 20px 40px rgba(0, 0, 0, 0.05);\r\n\r\n    @include tablet {\r\n      flex: 0 0 100%;\r\n      width: 100%;\r\n    }\r\n  }\r\n\r\n  &__map-img {\r\n    width: 100%;\r\n    height: auto;\r\n    display: block;\r\n    object-fit: cover;\r\n    transition: transform 0.5s ease;\r\n\r\n    &:hover {\r\n      transform: scale(1.02); // Легкий интерактив при наведении\r\n    }\r\n  }\r\n}\r\n\r\n\r\n\r\n.cta {\r\n\r\n\r\n  @include tablet {\r\n    padding: 40px 0;\r\n  }\r\n\r\n  &__card {\r\n    background-color: $color-bg-card;\r\n    border-radius: 40px;\r\n    padding: 35px 90px 35px 30px;\r\n    display: flex;\r\n    align-items: center;\r\n    justify-content: space-between;\r\n    gap: 40px;\r\n\r\n    @include tablet {\r\n      flex-direction: column;\r\n      padding: 40px 30px;\r\n      text-align: center;\r\n    }\r\n\r\n    @include mobile {\r\n      border-radius: 25px;\r\n      padding: 35px 20px;\r\n    }\r\n  }\r\n\r\n  &__content {\r\n    flex: 0 1 50%;\r\n  }\r\n\r\n  &__title {\r\n\r\n    font-size: 28px;\r\n    font-weight: 700;\r\n    line-height: 1.2;\r\n    color: #1D3511;\r\n    margin-bottom: 20px;\r\n\r\n    @include tablet {\r\n      font-size: 28px;\r\n    }\r\n\r\n    @include mobile {\r\n      font-size: 24px;\r\n    }\r\n  }\r\n\r\n  &__text {\r\n    font-size: 16px;\r\n    color: $color-text;\r\n    font-weight: 500;\r\n  }\r\n\r\n  &__form {\r\n    flex: 0 1 400px;\r\n    display: flex;\r\n    flex-direction: column;\r\n    gap: 15px;\r\n\r\n    @include tablet {\r\n      width: 100%;\r\n      max-width: 450px;\r\n    }\r\n  }\r\n\r\n  &__inputs {\r\n    display: flex;\r\n    flex-direction: column;\r\n    gap: 12px;\r\n  }\r\n\r\n\r\n\r\n    @include mobile {\r\n      font-size: 16px;\r\n      height: 60px;\r\n    }\r\n  }\r\n\r\n\r\n\r\n\r\n  .faq__wrapper{\r\n    padding: 30px 25px;\r\n    background-color: $color-bg-card;\r\n    border-radius: 30px;\r\n  }\r\n\r\n\r\n  .faq__tabs{\r\n\r\n    display: flex;\r\n    justify-content: space-between;\r\n    gap: 20px;\r\n    margin-bottom: 30px;\r\n\r\n    @include mobile {\r\n      flex-direction: column;\r\n      gap: 15px;\r\n    }\r\n\r\n    .faq__tab {\r\n      padding: 39px 0;\r\n      width: 100%;\r\n      border-radius: 30px;\r\n      font-size: 18px;\r\n      border: none;\r\n      background: $color-bg-main;\r\n      color: $color-text;\r\n      font-weight: 600;\r\n      cursor: pointer;\r\n      transition: $transition;\r\n\r\n      &.active {\r\n        background: $color-secondary;\r\n        color: $color-white;\r\n        box-shadow: 3px 3px 8px 0.5px rgba(0, 0, 0, 0.1);\r\n      }\r\n    }\r\n  }\r\n\r\n  .faq__content{\r\n    display: flex;\r\n    flex-direction: column;\r\n    gap: 20px;\r\n  }\r\n\r\n  .faq-item{\r\n    background-color: $color-bg-main;\r\n    padding: 25px;\r\n    border-radius: 30px;\r\n\r\n    &__header{\r\n      margin-bottom: 0;\r\n      font-weight: 500;\r\n    display: flex;\r\n    align-items: center;\r\n    justify-content: space-between;\r\n    width: 100%;\r\n    transition: $transition;\r\n\r\n    i {\r\n      font-size: 24px;\r\n      line-height: 1;\r\n      transition: transform 0.3s ease;\r\n   \r\n    }\r\n    }\r\n\r\n    &__body {\r\n    display: grid;\r\n    grid-template-rows: 0fr; // Свернуто по умолчанию\r\n    transition: grid-template-rows 0.3s ease;\r\n    overflow: hidden;\r\n  }\r\n\r\n    &__text{\r\n        min-height: 0; // Нужно для корректной работы grid-анимации\r\n \r\n        background-color: $color-bg-card;\r\n        font-weight: 500;\r\n        transition: $transition;\r\n        border-radius: 15px;\r\n    }\r\n  \r\n\r\n    // Состояние когда открыто\r\n  &.active {\r\n    &__header {\r\n      i {\r\n        transform: rotate(180deg); // Поворот стрелки\r\n      }\r\n    }\r\n    .faq-item__body {\r\n      margin-top: 20px;\r\n      grid-template-rows: 1fr; // Раскрываем\r\n\r\n     \r\n    }\r\n\r\n    .faq-item__text {\r\n      padding: 20px;\r\n    }\r\n  }\r\n}\r\n\r\n// Скрываем контент неактивных табов\r\n.faq__content {\r\n  display: none;\r\n  &.active {\r\n    display: flex;\r\n  }\r\n}\r\n\r\n\r\n\r\n\r\n\r\n.about-tabs {\r\n\r\n\r\n    &__nav {\r\n        display: flex;\r\n        justify-content: center;\r\n        gap: 100px;\r\n        margin-bottom: -1px; // Чтобы кнопки «приклеились» к блоку\r\n    }\r\n\r\n    &__btn {\r\n        padding: 15px 40px;\r\n    \r\n        font-size: 18px;\r\n        font-weight: 600;\r\n        border: none;\r\n        background: transparent;\r\n        color: $color-text;\r\n        cursor: pointer;\r\n        transition: $transition;\r\n        border-radius: 20px 20px 0 0;\r\n\r\n        &.active {\r\n            background: $color-secondary;\r\n            color: $color-white;\r\n        }\r\n    }\r\n\r\n    &__content {\r\n        display: none;\r\n        background: $color-secondary;\r\n        border-radius: 40px;\r\n        padding: 60px 80px;\r\n        color: #fff;\r\n\r\n        &.active {\r\n            display: block;\r\n        }\r\n\r\n        @include mobile {\r\n            padding: 40px 25px;\r\n            border-radius: 30px;\r\n        }\r\n    }\r\n\r\n    &__grid {\r\n        display: grid;\r\n        grid-template-columns: 1fr 1fr;\r\n        gap: 60px;\r\n        align-items: start;\r\n\r\n        @include mobile {\r\n            grid-template-columns: 1fr;\r\n            gap: 40px;\r\n        }\r\n    }\r\n\r\n    &__title {\r\n\r\n        font-size: 32px;\r\n                margin-bottom: 25px;\r\n    }\r\n\r\n    &__text {\r\n        font-size: 16px;\r\n        line-height: 1.6;\r\n     \r\n        opacity: 0.95;\r\n    }\r\n\r\n    &__list {\r\n        list-style: none;\r\n        padding: 0;\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 30px;\r\n    }\r\n\r\n    &__item {\r\n        position: relative;\r\n        padding-left: 20px;\r\n\r\n        &::before {\r\n            content: \"•\";\r\n            position: absolute;\r\n            left: 0;\r\n            top: 0;\r\n            font-size: 20px;\r\n        }\r\n\r\n        &-title {\r\n            display: block;\r\n            font-weight: 700;\r\n            font-size: 16px;\r\n            margin-bottom: 5px;\r\n            font-family: 'Gilroy', sans-serif;\r\n        }\r\n\r\n        &-desc {\r\n            font-size: 14px;\r\n            line-height: 1.4;\r\n            display: block;\r\n            opacity: 0.9;\r\n        }\r\n    }\r\n}\r\n\r\n\r\n\r\n.footer-cta{\r\n    margin-bottom: 100px;\r\n}\r\n\r\n.footer-cta__content{\r\n    display: flex;\r\n    justify-content: space-around;\r\n    align-items: center;\r\n\r\n    .call-us{\r\n        margin-top: 15px;\r\n        display: flex;\r\n        justify-content: space-between;\r\n    }\r\n}\r\n\r\n\r\n.footer-cta__content--right{\r\n    h3{\r\n        margin-bottom: 15px;\r\n    }\r\n\r\n    p{\r\n        font-weight: 500;\r\n    }\r\n}","@mixin tablet {\r\n\t@media (max-width: 991px) {\r\n\t\t@content;\r\n\t}\r\n}\r\n\r\n@mixin mobile {\r\n\t@media (max-width: 768px) {\r\n\t\t@content;\r\n\t}\r\n}\r\n",".footer {\r\n    background-color: $color-bg-card;\r\n    padding: 40px 0;\r\n    color: $color-text;\r\n\r\n    &__wrapper {\r\n        display: grid;\r\n        grid-template-columns: 200px 1fr; // Логотип (200px) и контент (остальное)\r\n        grid-template-areas:\r\n            \"logo header\"\r\n            \"logo main\";\r\n        column-gap: 60px;\r\n        row-gap: 40px;\r\n        align-items: start;\r\n\r\n        @include tablet {\r\n            grid-template-columns: 1fr;\r\n            grid-template-areas:\r\n                \"logo\"\r\n                \"header\"\r\n                \"main\";\r\n            row-gap: 30px;\r\n            text-align: center;\r\n        }\r\n    }\r\n\r\n    &__logo-block {\r\n        grid-area: logo;\r\n    }\r\n\r\n    &__logo {\r\n        max-width: 100%;\r\n        height: auto;\r\n    }\r\n\r\n    // --- ВЕРХНИЙ РЯД ---\r\n    &__header {\r\n        grid-area: header;\r\n        display: grid;\r\n        grid-template-columns: repeat(3, 1fr); // 3 равные колонки\r\n        gap: 30px;\r\n\r\n        @include mobile {\r\n            grid-template-columns: 1fr;\r\n        }\r\n\r\n        &--one {\r\n            h3 {\r\n                font-size: 20px;\r\n                font-weight: 600;\r\n                margin: 0 0 5px 0;\r\n            }\r\n            span {\r\n                font-size: 14px;\r\n                opacity: 0.4; \r\n                display: block;\r\n            }\r\n        }\r\n\r\n        &--two {\r\n            a {\r\n                font-size: 20px;\r\n                font-weight: 600;\r\n                opacity: .4;\r\n                text-decoration: none;\r\n                transition: $transition;\r\n\r\n                &:hover {\r\n                    opacity: 1;\r\n                }\r\n            }\r\n        }\r\n\r\n        &__three {\r\n            span {\r\n                display: block;\r\n                font-size: 12px;\r\n                line-height: 1.4;\r\n       \r\n            }\r\n        }\r\n    }\r\n\r\n    // --- НИЖНИЙ РЯД ---\r\n    &__main {\r\n        grid-area: main;\r\n        display: grid;\r\n        grid-template-columns: repeat(3, 1fr); // Колонки идеально совпадают с header\r\n        gap: 30px;\r\n\r\n        @include mobile {\r\n            grid-template-columns: 1fr;\r\n        }\r\n    }\r\n\r\n    &__list {\r\n        list-style: none;\r\n        padding: 0;\r\n        margin: 0;\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 14px;\r\n\r\n        li {\r\n            a {\r\n                color: inherit;\r\n                text-decoration: none;\r\n                font-size: 14px;\r\n                font-weight: 500;\r\n                transition: all 0.3s ease;\r\n\r\n                &:hover {\r\n                    opacity: 0.7;\r\n                    padding-left: 5px; // Легкий сдвиг при наведении\r\n                }\r\n            }\r\n        }\r\n    }\r\n\r\n    // --- СОЦСЕТИ ---\r\n    &__socials {\r\n        &-title {\r\n            display: block;\r\n            font-size: 14px;\r\n            font-weight: 500;\r\n            margin-bottom: 15px;\r\n        }\r\n\r\n        &-icons {\r\n            display: flex;\r\n            gap: 15px;\r\n\r\n            @include mobile {\r\n                justify-content: center;\r\n            }\r\n        }\r\n    }\r\n\r\n    &__social-link {\r\n        display: flex;\r\n        align-items: center;\r\n        justify-content: center;\r\n        width: 44px;\r\n        height: 44px;\r\n        background-color: $color-text;\r\n        color: $color-bg-card; // Иконки в цвет фона для контраста\r\n        font-weight: 400;\r\n        border-radius: 50%;\r\n        font-size: 24px;\r\n        text-decoration: none;\r\n        transition: all 0.3s ease;\r\n\r\n        &:hover {\r\n            transform: $transition;\r\n            background-color: $color-secondary;\r\n        }\r\